import os
from google.cloud import storage
from google.oauth2 import service_account
import pymysql
from flask import Flask, request

app = Flask(__name__)

def connect_to_db():
    user = os.environ['DB_USER']
    password = os.environ['DB_PASSWORD']
    database = os.environ['DB_NAME']
    host = 'localhost'  # or your Cloud SQL instance IP address or FQDN
    port = int(os.environ.get('PORT', 3306))

    connection = pymysql.connect(user=user, password=password,
                                  db=database, host=host, port=port)

    return connection

def build_query(params):
    query = "SELECT * FROM your_table WHERE "
    for key, value in params.items():
        if key != 'page' and key != 'limit':
            query += f"{key} = '{value}' AND "
    query = query[:-5]  # remove the last ' AND '

    return query + f" LIMIT {params['page']}, {params['limit']}"

@app.route('/search', methods=['GET'])
def search():
    params = request.args.to_dict()
    connection = connect_to_db()
    cursor = connection.cursor()
    query = build_query(params)

    cursor.execute(query)
    results = cursor.fetchall()

    # close the cursor and connection
    cursor.close()
    connection.close()

    return {'results': list(results)}